import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  categoria: string;
}

interface Pesaje {
  id: number;
  peso: number;
  fecha_pesaje: string;
  observaciones: string;
  usuario_nombre: string;
}

const Weights: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [selectedAnimal, setSelectedAnimal] = useState<number | null>(null);
  const [pesajes, setPesajes] = useState<Pesaje[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [editingPesajeId, setEditingPesajeId] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    animal_id: '',
    peso: '',
    fecha_pesaje: new Date().toISOString().split('T')[0],
    observaciones: ''
  });

  useEffect(() => {
    loadAnimals();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals?estado=activo');
      setAnimals(response.data);
    } catch (error) {
      console.error('Error cargando animales:', error);
    }
  };

  const loadPesajes = async (animalId: number) => {
    try {
      const response = await api.get(`/weights/animal/${animalId}`);
      setPesajes(response.data);
    } catch (error) {
      console.error('Error cargando pesajes:', error);
    }
  };

  const handleAnimalSelect = (animalId: number) => {
    setSelectedAnimal(animalId);
    loadPesajes(animalId);
    setFormData({...formData, animal_id: animalId.toString()});
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const data = {
        ...formData,
        animal_id: parseInt(formData.animal_id),
        peso: parseFloat(formData.peso)
      };

      if (editingPesajeId) {
        await api.put(`/weights/${editingPesajeId}`, data);
      } else {
        await api.post('/weights', data);
      }

      resetForm();
      if (selectedAnimal) {
        loadPesajes(selectedAnimal);
      }
    } catch (error) {
      console.error('Error guardando pesaje:', error);
      alert('Error guardando pesaje');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingPesajeId(null);
    setFormData({
      animal_id: selectedAnimal?.toString() || '',
      peso: '',
      fecha_pesaje: new Date().toISOString().split('T')[0],
      observaciones: ''
    });
  };

  const handleEditPesaje = (pesaje: Pesaje) => {
    setFormData({
      animal_id: selectedAnimal?.toString() || '',
      peso: pesaje.peso.toString(),
      fecha_pesaje: pesaje.fecha_pesaje,
      observaciones: pesaje.observaciones || ''
    });
    setEditingPesajeId(pesaje.id);
    setShowForm(true);
  };

  const handleDeletePesaje = async (id: number) => {
    if (window.confirm('¿Estás seguro de eliminar este pesaje?')) {
      try {
        await api.delete(`/weights/${id}`);
        if (selectedAnimal) {
          loadPesajes(selectedAnimal);
        }
      } catch (error) {
        console.error('Error eliminando pesaje:', error);
        alert('Error eliminando pesaje');
      }
    }
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h1>Control de Pesajes</h1>
        {selectedAnimal && (
          <button 
            className="btn btn-primary"
            onClick={() => setShowForm(!showForm)}
          >
            {showForm ? 'Cancelar' : 'Nuevo Pesaje'}
          </button>
        )}
      </div>

      <div className="grid grid-2">
        {/* Lista de Animales */}
        <div className="card">
          <h3>Seleccionar Animal</h3>
          {animals.length > 0 ? (
            <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
              {animals.map(animal => (
                <div 
                  key={animal.id}
                  onClick={() => handleAnimalSelect(animal.id)}
                  style={{
                    padding: '12px',
                    margin: '5px 0',
                    backgroundColor: selectedAnimal === animal.id ? '#e3f2fd' : '#f8f9fa',
                    border: selectedAnimal === animal.id ? '2px solid #2196f3' : '1px solid #ddd',
                    borderRadius: '4px',
                    cursor: 'pointer',
                    transition: 'all 0.2s'
                  }}
                >
                  <div style={{ fontWeight: 'bold' }}>{animal.identificador_unico}</div>
                  <div style={{ fontSize: '14px', color: '#666' }}>
                    {animal.nombre || 'Sin nombre'} - {animal.categoria}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p style={{ textAlign: 'center', color: '#666', padding: '20px' }}>
              No hay animales disponibles
            </p>
          )}
        </div>

        {/* Formulario de Pesaje */}
        <div className="card">
          {showForm ? (
            <div>
              <h3>{editingPesajeId ? '✏️ Editar Pesaje' : '➕ Registrar Pesaje'}</h3>
              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <label>Peso (kg):</label>
                  <input
                    type="number"
                    step="0.1"
                    className="form-control"
                    value={formData.peso}
                    onChange={(e) => setFormData({...formData, peso: e.target.value})}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Fecha:</label>
                  <input
                    type="date"
                    className="form-control"
                    value={formData.fecha_pesaje}
                    onChange={(e) => setFormData({...formData, fecha_pesaje: e.target.value})}
                    required
                  />
                </div>
                <div className="form-group">
                  <label>Observaciones:</label>
                  <textarea
                    className="form-control"
                    rows={3}
                    value={formData.observaciones}
                    onChange={(e) => setFormData({...formData, observaciones: e.target.value})}
                  />
                </div>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <button type="submit" className="btn btn-success">
                    {editingPesajeId ? '💾 Actualizar' : '💾 Guardar'} Pesaje
                  </button>
                  <button type="button" className="btn btn-secondary" onClick={resetForm}>
                    ❌ Cancelar
                  </button>
                </div>
              </form>
            </div>
          ) : (
            <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
              {selectedAnimal ? (
                <div>
                  <div style={{ fontSize: '48px', marginBottom: '15px' }}>⚖️</div>
                  <p>Selecciona "Nuevo Pesaje" para registrar el peso del animal</p>
                </div>
              ) : (
                <div>
                  <div style={{ fontSize: '48px', marginBottom: '15px' }}>🐷</div>
                  <p>Selecciona un animal de la lista para ver sus pesajes</p>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Historial de Pesajes */}
      {selectedAnimal && pesajes.length > 0 && (
        <div className="card mt-3">
          <div className="card-header">
            <h3 className="card-title">⚖️ Historial de Pesajes</h3>
          </div>
          <div className="table-container">
            <table className="table">
              <thead>
                <tr>
                  <th>Fecha</th>
                  <th>Peso (kg)</th>
                  <th>Observaciones</th>
                  <th>Registrado por</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {pesajes.map(pesaje => (
                  <tr key={pesaje.id}>
                    <td>{new Date(pesaje.fecha_pesaje).toLocaleDateString()}</td>
                    <td style={{ fontWeight: 'bold', color: '#2196f3' }}>{pesaje.peso} kg</td>
                    <td>{pesaje.observaciones || '-'}</td>
                    <td>{pesaje.usuario_nombre || '-'}</td>
                    <td>
                      <div style={{ display: 'flex', gap: '5px' }}>
                        <button 
                          className="btn btn-warning btn-sm"
                          onClick={() => handleEditPesaje(pesaje)}
                          title="Editar pesaje"
                        >
                          ✏️
                        </button>
                        <button 
                          className="btn btn-danger btn-sm"
                          onClick={() => handleDeletePesaje(pesaje.id)}
                          title="Eliminar pesaje"
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {selectedAnimal && pesajes.length === 0 && (
        <div className="card mt-3">
          <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
            <div style={{ fontSize: '48px', marginBottom: '15px' }}>📊</div>
            <p>No hay pesajes registrados para este animal</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default Weights;
